class Pointer:
 def __init__(self, array):
 self.array = array
 self.index = 0

 def increment(self):
 self.index += 1

 def get_value(self):
 return self.array[self.index]

array = [1, 2, 3, 4, 5]
pointer = Pointer(array)
for _ in range(len(array)):
 print(pointer.get_value())
 pointer.increment()

#include <stdio.h>

int main() {
 int array[] = {1, 2, 3, 4, 5};
 int *pointer = array;
 for (int i = 0; i < 5; i++) {
 printf("%d ", *pointer);
 pointer++;
 }
 return 0;
}
